//! The inline `--output-schema` text for the three norn-backed stages,
//! byte-identical to the Gleam string constants in
//! `../../src/stacked_dev/locals.gleam` (`scout_output_schema`,
//! `dev_output_schema`, `review_output_schema`). Each is the stage-contract
//! schema the drift gate pins to the design-system canon (CN7); passing it
//! inline means there is no schema file to resolve in the workspace.

/// The scout-report stage-contract schema (`locals.scout_output_schema`).
pub const SCOUT_OUTPUT_SCHEMA: &str = "{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"title\":\"Scout Report\",\"description\":\"Structured output contract for the scout stage: read-only codebase exploration that gathers implementation context per requirement. The enrichments entries are appended in place to the brief's requirements as their scout blocks.\",\"type\":\"object\",\"required\":[\"summary\",\"enrichments\",\"verification\"],\"additionalProperties\":false,\"properties\":{\"summary\":{\"type\":\"string\",\"description\":\"2-3 sentences orienting the implementer\"},\"enrichments\":{\"type\":\"array\",\"items\":{\"type\":\"object\",\"required\":[\"id\",\"files\",\"context\",\"approach\",\"notes\"],\"additionalProperties\":false,\"properties\":{\"id\":{\"type\":\"string\",\"pattern\":\"^R\\\\d+$\",\"description\":\"R# id from the brief — one entry per requirement, no omissions\"},\"files\":{\"type\":\"array\",\"items\":{\"type\":\"string\"},\"description\":\"Key files relevant to this R# (path:line-range — brief note). 2-5 per R#, chosen to save the implementer time, not to catalogue.\"},\"context\":{\"type\":\"array\",\"items\":{\"type\":\"string\"},\"description\":\"Key findings: conventions to match, type signatures, gotchas. 2-4 per R#.\"},\"approach\":{\"type\":\"string\",\"description\":\"How to implement this R# — one paragraph, concrete\"},\"notes\":{\"type\":\"string\",\"description\":\"Anything non-obvious the brief might not have considered: edge cases, integration gotchas. Empty string if none.\"}}}},\"verification\":{\"type\":\"array\",\"items\":{\"type\":\"string\"},\"description\":\"Concrete checks to run after implementation, discovered during exploration\"}}}";

/// The dev-report stage-contract schema (`locals.dev_output_schema`).
pub const DEV_OUTPUT_SCHEMA: &str = "{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"title\":\"Dev Report\",\"description\":\"Structured output contract for the dev stage: implementation of every requirement in the brief. The enrichments entries are appended in place to the brief's requirements as their dev blocks. The attestation records what the agent BELIEVES — the workflow runs the real gate afterwards and stores both; the attestation is never trusted as the gate.\",\"type\":\"object\",\"required\":[\"summary\",\"commit_message\",\"enrichments\",\"attestation\"],\"additionalProperties\":false,\"properties\":{\"summary\":{\"type\":\"string\",\"description\":\"1-2 sentences on what was done\"},\"commit_message\":{\"type\":\"string\",\"description\":\"Conventional-commits style message for this round's commit\"},\"enrichments\":{\"type\":\"array\",\"items\":{\"type\":\"object\",\"required\":[\"id\",\"status\",\"files_changed\",\"how\",\"deviation\",\"checklist\",\"stories\"],\"additionalProperties\":false,\"properties\":{\"id\":{\"type\":\"string\",\"pattern\":\"^R\\\\d+$\",\"description\":\"R# id — one entry per requirement, blocked ones included with status blocked\"},\"status\":{\"type\":\"string\",\"enum\":[\"implemented\",\"blocked\"]},\"files_changed\":{\"type\":\"array\",\"items\":{\"type\":\"object\",\"required\":[\"path\",\"change\",\"note\"],\"additionalProperties\":false,\"properties\":{\"path\":{\"type\":\"string\"},\"change\":{\"type\":\"string\",\"enum\":[\"created\",\"modified\",\"deleted\"]},\"note\":{\"type\":\"string\"}}}},\"how\":{\"type\":\"string\",\"description\":\"How this requirement was met — the rationale and shape of the change, not a diff narration\"},\"deviation\":{\"type\":\"string\",\"description\":\"Empty if the scouted plan was followed; otherwise what changed and why — silent deviation is a review finding\"},\"checklist\":{\"type\":\"array\",\"items\":{\"type\":\"object\",\"required\":[\"id\",\"done\",\"note\"],\"additionalProperties\":false,\"properties\":{\"id\":{\"type\":\"string\",\"pattern\":\"^C\\\\d+$\"},\"done\":{\"type\":\"boolean\"},\"note\":{\"type\":\"string\"}}},\"description\":\"Delivery claim per C# assigned to this R#\"},\"stories\":{\"type\":\"array\",\"items\":{\"type\":\"object\",\"required\":[\"id\",\"satisfied\",\"note\"],\"additionalProperties\":false,\"properties\":{\"id\":{\"type\":\"string\",\"pattern\":\"^S\\\\d+$\"},\"satisfied\":{\"type\":\"boolean\"},\"note\":{\"type\":\"string\"}}},\"description\":\"Satisfaction claim per S# assigned to this R#\"}}}},\"attestation\":{\"type\":\"object\",\"required\":[\"no_panics\",\"no_unsafe\",\"boundaries_respected\",\"tests_pass\"],\"additionalProperties\":false,\"properties\":{\"no_panics\":{\"type\":\"boolean\",\"description\":\"No unwrap/expect/panic/todo in library code\"},\"no_unsafe\":{\"type\":\"boolean\",\"description\":\"No unsafe blocks added\"},\"boundaries_respected\":{\"type\":\"boolean\",\"description\":\"All SHALL NOT boundaries observed\"},\"tests_pass\":{\"type\":\"boolean\",\"description\":\"The agent's belief — the workflow measures the truth at the gate\"}}}}}";

/// The review-report stage-contract schema (`locals.review_output_schema`).
pub const REVIEW_OUTPUT_SCHEMA: &str = "{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"title\":\"Review Report\",\"description\":\"Structured output contract for the adversarial review stage. The reviewer verifies the ACTUAL DIFF against each acceptance criterion — never the dev's claims — then hardens. Verdict and fixes are both recorded; there is no severity taxonomy because there are no minor issues: everything found is fixed or named as an issue. The enrichments entries are appended in place to the brief's requirements as their review blocks.\",\"type\":\"object\",\"required\":[\"summary\",\"commit_message\",\"enrichments\",\"verification\"],\"additionalProperties\":false,\"properties\":{\"summary\":{\"type\":\"string\",\"description\":\"The honest overall read — what is solid, what was found, what was fixed\"},\"commit_message\":{\"type\":\"string\",\"description\":\"Conventional-commits style message for the harden commit; empty string when the harden pass changed nothing\"},\"enrichments\":{\"type\":\"array\",\"items\":{\"type\":\"object\",\"required\":[\"id\",\"alignment\",\"acceptance\",\"checklist\",\"stories\",\"issues\",\"fixes\"],\"additionalProperties\":false,\"properties\":{\"id\":{\"type\":\"string\",\"pattern\":\"^R\\\\d+$\",\"description\":\"R# id — one entry per requirement\"},\"alignment\":{\"type\":\"string\",\"enum\":[\"aligned\",\"drifted\",\"fixed\"],\"description\":\"aligned = implementation matches spec; drifted = it does not and remains so (a failing state); fixed = it drifted and the harden pass corrected it\"},\"acceptance\":{\"type\":\"array\",\"items\":{\"type\":\"object\",\"required\":[\"criterion\",\"met\",\"evidence\"],\"additionalProperties\":false,\"properties\":{\"criterion\":{\"type\":\"string\",\"description\":\"The acceptance criterion verbatim from the brief\"},\"met\":{\"type\":\"boolean\"},\"evidence\":{\"type\":\"string\",\"description\":\"What in the diff proves it: file:line, test name, command output — not the dev report\"}}},\"description\":\"One verdict per acceptance criterion. A single boolean for the whole requirement is not a review.\"},\"checklist\":{\"type\":\"array\",\"items\":{\"type\":\"string\",\"pattern\":\"^C\\\\d+$\"},\"description\":\"C-numbers VERIFIED delivered (verification flips done in the cluster checklist, not the dev's claim)\"},\"stories\":{\"type\":\"array\",\"items\":{\"type\":\"string\",\"pattern\":\"^S\\\\d+$\"},\"description\":\"S-numbers verified satisfied\"},\"issues\":{\"type\":\"array\",\"items\":{\"type\":\"string\"},\"description\":\"Everything found, fixed or not — an issue that was fixed still gets recorded here with its fix below\"},\"fixes\":{\"type\":\"array\",\"items\":{\"type\":\"string\"},\"description\":\"What the harden pass changed\"}}}},\"verification\":{\"type\":\"array\",\"items\":{\"type\":\"object\",\"required\":[\"criterion\",\"passed\",\"note\"],\"additionalProperties\":false,\"properties\":{\"criterion\":{\"type\":\"string\",\"description\":\"Brief-level verification step, verbatim\"},\"passed\":{\"type\":\"boolean\"},\"note\":{\"type\":\"string\"}}},\"description\":\"The brief's cross-cutting verification steps, each actually executed\"}}}";
